# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messaging, performance analytics and reporting.  The implementation only
relies on the Python standard library and is fully deterministic when a
custom ``now`` callable (clock) is injected.

The public surface is exercised by ``test_solution.py``.  The module exposes:

* Enums:        ``TaskStatus``, ``UserRole``, ``ReportFormat``, ``ReportType``
* Exceptions:   ``TeamCollaborationError`` and its specialised subclasses
* Data records: ``User``, ``Project``, ``Task``, ``Message``, ``Attachment``,
                ``Rating``
* Facade:       ``TeamCollaborationManager``

Design notes
------------
* A single re-entrant lock is shared by the manager and every sub-store so
  that cross-entity operations are atomic.  The shared identity is part of the
  public contract (see ``test_shared_lock_identity``).
* Every getter returns a deep copy so callers can never mutate internal state
  by holding on to a returned object (see ``TestGetterIsolation``).
* Identifiers are globally unique and monotonically increasing, starting at 1.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from collections import defaultdict
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Sequence, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a user may hold."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Logical report kinds produced by the manager."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an action conflicts with the current state."""


# ---------------------------------------------------------------------------
# Data records
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: Optional[datetime] = None


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    description: str
    status: TaskStatus
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal infrastructure
# ---------------------------------------------------------------------------
class _IdAllocator:
    """Thread-safe, monotonically increasing id generator (starts at 1)."""

    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self._value = 0

    def next(self) -> int:
        with self._lock:
            self._value += 1
            return self._value


class _UserStore:
    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self.items: Dict[int, User] = {}
        self.by_username: Dict[str, int] = {}
        self.by_email: Dict[str, int] = {}


class _ProjectStore:
    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self.items: Dict[int, Project] = {}


class _TaskStore:
    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self.items: Dict[int, Task] = {}
        self.by_project: Dict[int, set] = defaultdict(set)
        self.by_assignee: Dict[int, set] = defaultdict(set)


class _MessageStore:
    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self.items: Dict[int, Message] = {}
        self.by_project: Dict[int, set] = defaultdict(set)
        self.by_task: Dict[int, set] = defaultdict(set)


class _PerformanceStore:
    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self.ratings: Dict[int, Rating] = {}
        self.by_ratee: Dict[int, set] = defaultdict(set)


class _ReportStore:
    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock


def _clone(obj):
    """Return an isolated deep copy of a stored record."""

    return copy.deepcopy(obj)


def _stringify(value) -> str:
    """Render a report value as a flat string for tabular export."""

    if value is None:
        return ""
    if isinstance(value, Enum):
        return str(value.value)
    if isinstance(value, float):
        return repr(value)
    return str(value)


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory facade coordinating all collaboration features."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._ids = _IdAllocator(self._lock)

        # Sub-stores share the manager's lock so cross-entity work is atomic.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- internal lookup helpers (assume the lock is already held) ----------
    def _require_user(self, user_id: int) -> User:
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_email(email: str) -> str:
        if email is None:
            raise ValidationError("email is required")
        cleaned = str(email).strip()
        if not cleaned:
            raise ValidationError("email is required")
        if "@" not in cleaned:
            raise ValidationError("email must contain '@'")
        return cleaned

    # -----------------------------------------------------------------------
    # User management
    # -----------------------------------------------------------------------
    def register_user(
        self,
        username: str,
        email: str,
        role: UserRole = UserRole.MEMBER,
    ) -> User:
        with self._lock:
            if username is None or not str(username).strip():
                raise ValidationError("username is required")
            cleaned_name = str(username).strip()
            cleaned_email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if cleaned_name in self.users.by_username:
                raise DuplicateError("username already exists")
            if cleaned_email in self.users.by_email:
                raise DuplicateError("email already exists")

            user_id = self._ids.next()
            user = User(user_id, cleaned_name, cleaned_email, role, self._now())
            self.users.items[user_id] = user
            self.users.by_username[cleaned_name] = user_id
            self.users.by_email[cleaned_email] = user_id
            return _clone(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return _clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [_clone(self.users.items[i]) for i in sorted(self.users.items)]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)

            new_name = None
            if username is not None:
                new_name = str(username).strip()
                if not new_name:
                    raise ValidationError("username is required")
                owner = self.users.by_username.get(new_name)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already exists")

            new_email = None
            if email is not None:
                new_email = self._validate_email(email)
                owner = self.users.by_email.get(new_email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if new_name is not None:
                self.users.by_username.pop(user.username, None)
                user.username = new_name
                self.users.by_username[new_name] = user_id
            if new_email is not None:
                self.users.by_email.pop(user.email, None)
                user.email = new_email
                self.users.by_email[new_email] = user_id
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task_id in self.tasks.by_assignee.get(user_id, set()):
                task = self.tasks.items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task")

            self.users.items.pop(user_id, None)
            self.users.by_username.pop(user.username, None)
            self.users.by_email.pop(user.email, None)
            # Any remaining (completed) task references are detached.
            for task_id in self.tasks.by_assignee.pop(user_id, set()):
                task = self.tasks.items.get(task_id)
                if task is not None:
                    task.assignee_id = None

    # -----------------------------------------------------------------------
    # Project management
    # -----------------------------------------------------------------------
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            self._require_user(owner_id)
            if name is None or not str(name).strip():
                raise ValidationError("project name is required")
            if start_date is None or end_date is None:
                raise ValidationError("start and end dates are required")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")

            project_id = self._ids.next()
            project = Project(
                project_id,
                str(name).strip(),
                description or "",
                start_date,
                end_date,
                owner_id,
                self._now(),
            )
            self.projects.items[project_id] = project
            return _clone(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return _clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                _clone(self.projects.items[i]) for i in sorted(self.projects.items)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        description: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date

            if name is not None and not str(name).strip():
                raise ValidationError("project name is required")
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not None:
                project.name = str(name).strip()
            if description is not None:
                project.description = description
            project.start_date = new_start
            project.end_date = new_end
            return _clone(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)

            for task_id in list(self.tasks.by_project.get(project_id, set())):
                task = self.tasks.items.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    self.tasks.by_assignee.get(task.assignee_id, set()).discard(
                        task_id
                    )
                for message_id in list(self.messages.by_task.get(task_id, set())):
                    self._remove_message(message_id)
                self.messages.by_task.pop(task_id, None)
            self.tasks.by_project.pop(project_id, None)

            for message_id in list(self.messages.by_project.get(project_id, set())):
                self._remove_message(message_id)
            self.messages.by_project.pop(project_id, None)

            self.projects.items.pop(project_id, None)

    # -----------------------------------------------------------------------
    # Task management
    # -----------------------------------------------------------------------
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
        description: str = "",
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if assignee_id is not None:
                self._require_user(assignee_id)
            if title is None or not str(title).strip():
                raise ValidationError("task title is required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task_id = self._ids.next()
            task = Task(
                task_id,
                project_id,
                str(title).strip(),
                description or "",
                TaskStatus.NOT_STARTED,
                assignee_id,
                deadline,
                None,
                None,
                self._now(),
            )
            self.tasks.items[task_id] = task
            self.tasks.by_project[project_id].add(task_id)
            if assignee_id is not None:
                self.tasks.by_assignee[assignee_id].add(task_id)
            return _clone(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return _clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks.by_project.get(project_id, set()))
            return [_clone(self.tasks.items[i]) for i in ids]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self.tasks.by_assignee.get(user_id, set()))
            return [_clone(self.tasks.items[i]) for i in ids]

    def assign_task(self, task_id: int, user_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(user_id)
            if task.assignee_id is not None and task.assignee_id != user_id:
                self.tasks.by_assignee.get(task.assignee_id, set()).discard(task_id)
            task.assignee_id = user_id
            self.tasks.by_assignee[user_id].add(task_id)
            return _clone(task)

    def reassign_task(self, task_id: int, user_id: int) -> Task:
        # Re-assignment shares the exact semantics of assignment.
        return self.assign_task(task_id, user_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if task.assignee_id is not None:
                self.tasks.by_assignee.get(task.assignee_id, set()).discard(task_id)
                task.assignee_id = None
            return _clone(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")
            task = self._require_task(task_id)
            now = self._now()

            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return _clone(task)

    # -----------------------------------------------------------------------
    # Messaging
    # -----------------------------------------------------------------------
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[Sequence[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            target_count = sum(
                1 for target in (project_id, task_id) if target is not None
            )
            if target_count != 1:
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            self._require_user(author_id)
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            body_text = "" if body is None else str(body)
            raw_attachments = list(attachments) if attachments else []
            if not body_text.strip() and not raw_attachments:
                raise ValidationError("message body or an attachment is required")

            now = self._now()
            attachment_objs = [
                Attachment(str(filename), len(data), author_id, now)
                for filename, data in raw_attachments
            ]

            message_id = self._ids.next()
            message = Message(
                message_id,
                author_id,
                body_text,
                project_id,
                task_id,
                parent_id,
                attachment_objs,
                now,
                None,
            )
            self.messages.items[message_id] = message
            if project_id is not None:
                self.messages.by_project[project_id].add(message_id)
            if task_id is not None:
                self.messages.by_task[task_id].add(message_id)
            return _clone(message)

    def edit_message(
        self, message_id: int, editor_id: int, new_body: str
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            if new_body is None or not str(new_body).strip():
                raise ValidationError("message body is required")
            message.body = str(new_body)
            message.edited_at = self._now()
            return _clone(message)

    def add_attachment(
        self, message_id: int, user_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may add attachments")
            if filename is None or not str(filename).strip():
                raise ValidationError("filename is required")
            size = len(data) if data is not None else 0
            message.attachments.append(
                Attachment(str(filename), size, user_id, self._now())
            )
            return _clone(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages.by_project.get(project_id, set()))
            return [_clone(self.messages.items[i]) for i in ids]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages.by_task.get(task_id, set()))
            return [_clone(self.messages.items[i]) for i in ids]

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            self._remove_message(message_id)

    def _remove_message(self, message_id: int) -> None:
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            self.messages.by_project.get(message.project_id, set()).discard(
                message_id
            )
        if message.task_id is not None:
            self.messages.by_task.get(message.task_id, set()).discard(message_id)

    # -----------------------------------------------------------------------
    # Performance dashboard
    # -----------------------------------------------------------------------
    def _completion_rate_raw(self, user_id: int) -> float:
        task_ids = self.tasks.by_assignee.get(user_id, set())
        total = len(task_ids)
        if total == 0:
            return 0.0
        completed = sum(
            1
            for tid in task_ids
            if self.tasks.items[tid].status == TaskStatus.COMPLETED
        )
        return completed / total

    def _average_completion_time_raw(self, user_id: int) -> Optional[float]:
        durations = []
        for tid in self.tasks.by_assignee.get(user_id, set()):
            task = self.tasks.items[tid]
            if (
                task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append(
                    (task.completed_at - task.started_at).total_seconds()
                )
        if not durations:
            return None
        return sum(durations) / len(durations)

    def _ratings_summary_raw(self, user_id: int) -> Dict[str, object]:
        ids = sorted(self.performance.by_ratee.get(user_id, set()))
        ratings = [self.performance.ratings[i] for i in ids]
        count = len(ratings)
        average = sum(r.score for r in ratings) / count if count else 0.0
        return {
            "count": count,
            "average": average,
            "ratings": [_clone(r) for r in ratings],
        }

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            return self._completion_rate_raw(user_id)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            return self._average_completion_time_raw(user_id)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer in 1..5")
            if score < 1 or score > 5:
                raise ValidationError("score must be in 1..5")
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)

            rating_id = self._ids.next()
            rating = Rating(
                rating_id,
                rater_id,
                ratee_id,
                score,
                feedback or "",
                task_id,
                self._now(),
            )
            self.performance.ratings[rating_id] = rating
            self.performance.by_ratee[ratee_id].add(rating_id)
            return _clone(rating)

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            return self._ratings_summary_raw(user_id)

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_user(user_id)
            task_ids = self.tasks.by_assignee.get(user_id, set())
            total = len(task_ids)
            completed = in_progress = not_started = 0
            for tid in task_ids:
                status = self.tasks.items[tid].status
                if status == TaskStatus.COMPLETED:
                    completed += 1
                elif status == TaskStatus.IN_PROGRESS:
                    in_progress += 1
                else:
                    not_started += 1

            summary = self._ratings_summary_raw(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": self._average_completion_time_raw(
                    user_id
                ),
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }

    # -----------------------------------------------------------------------
    # Reports
    # -----------------------------------------------------------------------
    def project_progress_report(self, project_id: int) -> Dict[str, object]:
        with self._lock:
            self._require_project(project_id)
            task_ids = self.tasks.by_project.get(project_id, set())
            tasks = [self.tasks.items[i] for i in task_ids]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.deadline < now
                and task.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, Dict[str, int]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {
                        "total": 0,
                        "completed": 0,
                        "in_progress": 0,
                        "not_started": 0,
                    },
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    bucket["in_progress"] += 1
                else:
                    bucket["not_started"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def _user_performance_row(
        self, user_id: int, tasks: List[Task]
    ) -> Dict[str, object]:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        average_time = sum(durations) / len(durations) if durations else None
        summary = self._ratings_summary_raw(user_id)
        user = self.users.items.get(user_id)
        return {
            "user_id": user_id,
            "username": user.username if user is not None else None,
            "total_tasks": total,
            "completed_tasks": completed,
            "completion_rate": (completed / total) if total else 0.0,
            "average_completion_time": average_time,
            "rating_count": summary["count"],
            "rating_average": summary["average"],
        }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                scoped_ids = self.tasks.by_project.get(project_id, set())
                tasks_by_user: Dict[int, List[Task]] = defaultdict(list)
                for tid in scoped_ids:
                    task = self.tasks.items[tid]
                    if task.assignee_id is not None:
                        tasks_by_user[task.assignee_id].append(task)
                user_ids = sorted(tasks_by_user.keys())
            else:
                tasks_by_user = defaultdict(list)
                for user_id in self.users.items:
                    for tid in self.tasks.by_assignee.get(user_id, set()):
                        tasks_by_user[user_id].append(self.tasks.items[tid])
                user_ids = sorted(self.users.items.keys())

            rows = [
                self._user_performance_row(uid, tasks_by_user.get(uid, []))
                for uid in user_ids
            ]
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "scope_project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            user = self._require_user(user_id)
            ids = sorted(self.tasks.by_assignee.get(user_id, set()))
            tasks = [self.tasks.items[i] for i in ids]
            row = self._user_performance_row(user_id, tasks)
            row.update(
                {
                    "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                    "username": user.username,
                    "tasks": [_clone(t) for t in tasks],
                }
            )
            return row

    # -----------------------------------------------------------------------
    # Export
    # -----------------------------------------------------------------------
    def export_report(self, report: Dict[str, object], fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _export_csv(report: Dict[str, object]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(
            isinstance(row, dict) for row in rows
        ):
            columns: List[str] = []
            for row in rows:
                for key in row:
                    if key not in columns:
                        columns.append(key)
            writer.writerow(columns)
            for row in rows:
                writer.writerow([_stringify(row.get(col)) for col in columns])
        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                writer.writerow([key, _stringify(value)])
        return buffer.getvalue()

    @staticmethod
    def _export_pdf(report: Dict[str, object]) -> bytes:
        title = _stringify(report.get("report_type", "report")) or "report"
        lines = [title]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, _stringify(value)))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF writer (valid 1.4 document with a cross-reference table)
# ---------------------------------------------------------------------------
def _pdf_escape(text: str) -> str:
    return (
        text.replace("\\", "\\\\")
        .replace("(", "\\(")
        .replace(")", "\\)")
        .replace("\r", " ")
        .replace("\n", " ")
    )


def _build_pdf(lines: Sequence[str]) -> bytes:
    content_parts = ["BT", "/F1 12 Tf", "14 TL", "50 760 Td"]
    for index, line in enumerate(lines):
        content_parts.append("({0}) Tj".format(_pdf_escape(str(line))))
        if index != len(lines) - 1:
            content_parts.append("T*")
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>",
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets: List[int] = []
    for number, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(number).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_position = len(pdf)
    total = len(objects) + 1
    pdf += b"xref\n0 " + str(total).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += ("%010d 00000 n \n" % offset).encode("ascii")
    pdf += (
        b"trailer\n<< /Size "
        + str(total).encode("ascii")
        + b" /Root 1 0 R >>\nstartxref\n"
        + str(xref_position).encode("ascii")
        + b"\n%%EOF\n"
    )
    return bytes(pdf)


